 14→/**
 15→ * // 直接把关注的人都发到邮箱.
 16→ */
 17→class DailyReportJob extends MyJob
 18→{
 19→    protected $jobParams;
 20→
 21→    public function __construct($jobParams = '')
 22→    {
 23→        $this->jobParams = $jobParams;
 24→    }
 25→
 26→    public function handle(): bool
 27→    {
 28→        info('发送日报邮件 Job 开始');
 29→        $arg = $this->jobParams;
 30→        info('发送日报邮件 取数参数'.$this->jobParams);
 31→        $msg2 = '上个工作日';
 32→        if (!$arg) {
 33→            $today = ShiftCalendar::where('full_date', date('Y-m-d'))->first();
 34→            if ($today == null || $today->is_weekend || $today->is_holiday) {
 35→                info('发送日报邮件 不是工作日，不发送邮件');
 36→                info('[ScheduleJob][DailyReportJob] finished #1');
 37→                return false;
 38→            }
 39→            $shift = ShiftCalendar::where('is_weekend', 0)->where('is_holiday', 0)->where('full_date', '<', date('Y-m-d'))
 40→                ->orderByDesc('full_date')->limit(1)->first();
 41→            if ($shift == null) {
 42→                info('发送日报邮件 不是工作日2，不发送邮件');
 43→                info('[ScheduleJob][DailyReportJob] finished #2');
 44→                return false;
 45→            }
 46→            $full_date = $shift->full_date;
 47→        } else {
 48→            $full_date = $arg;
 49→            $msg2 = '';
 50→        }
 51→        info('发送日报邮件 Job 日期 '.$full_date);
 52→
 53→        $mcs = MailConfig::where('type', 'like', '%daily_report_%')->get()->toArray();
 54→        if (empty($mcs)) {
 55→            info('发送日报邮件 没有人配置邮件通知，不发送邮件');
 56→            info('[ScheduleJob][DailyReportJob] finished #3');
 57→            return false;
 58→        }
 59→        $oneEmailLimit = 50000;
 60→        foreach ($mcs as $mc) {
 61→            $emailAllCount = 0;
 62→            $emailOne = 0;
 63→            try {
 64→                $config = $mc['config'];
 65→                $toEmails = Arr::get($config, 'to_email');
 66→                $sfuser_token = Arr::get($config, 'sfuser_authorized_token', '');
 67→                if (!$sfuser_token) {
 68→                    info('发送日报邮件 没有 tokens 跳过'.my_json_encode($mc));
 69→                    continue;
 70→                }
 71→                if (!$toEmails) {
 72→                    info('发送日报邮件 没有 emails 跳过'.my_json_encode($mc));
 73→                    continue;
 74→                }
 75→                $sfuserId = substr($mc['type'], strpos($mc['type'], 'daily_report_') + 13);
 76→                if (!$sfuserId) {
 77→                    info('发送日报邮件 没有 sfuserId 跳过'.my_json_encode($mc));
 78→                    continue;
 79→                }
 80→                $dailyService = app(DailyReportService::class);
 81→                $focus_user_ids = $dailyService->getSubordinates($sfuserId);
 82→
 83→                $data = $dailyService->getOthersDailyReportListEnable(
 84→                    $full_date,
 85→                    $full_date,
 86→                    $sfuserId,
 87→                    $focus_user_ids['focus_users'],
 88→                    10000
 89→                );
 90→                if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
 91→                    info('发送日报邮件 没有数据跳过'.$sfuserId.my_json_encode($mc));
 92→                    continue;
 93→                }
 94→
 95→                $user = Sfuser::where('id', $sfuserId)->first();
 96→                $nicknameOk = '';
 97→                if (empty($user)) {
 98→                    info('发送日报邮件 人不对 '.$sfuserId.my_json_encode($mc));
 99→                    $id2Nicknames = SfuserNicknameMapService::app()->ids2Nicknames([$sfuserId]);
100→                    if (!empty($id2Nicknames)) {
101→                        $nicknameOk = $this->encr(Arr::get($id2Nicknames, $sfuserId, ''));
102→                    }
103→                } else {
104→                    $nicknameOk = $this->encr($user->nickname);
105→                }
106→
107→                // 更
108→                $content = '<p >Dear '.$nicknameOk.',</p><p >以下是您关注同事'.$msg2.'的日报：</p>';
109→                // d
110→                $no = 0;
111→                foreach ($data['reports']['report_list'] as $report) {
112→                    $nickname1 = '';
113→                    if (empty($report['data']['nickname'])) {
114→                        if (!empty($report['sfuser_id'])) {
115→                            $sfuser_id1 = Sfuser::where('id', $report['sfuser_id'])->first();
116→                            if (!empty($sfuser_id1)) {
117→                                $nickname1 = $sfuser_id1->nickname;
118→                            }
119→                        }
120→                    } else {
121→                        $nickname1 = $report['data']['nickname'];
122→                    }
123→                    if (empty($nickname1)) {
124→                        info('发送日报邮件 空数据 '.my_json_encode($report));
125→                        continue;
126→                    }
127→                    $nickname = $this->encr($nickname1);
128→                    $contentO = $this->encr($report['content']);
129→                    $contentO = '<div style="border: 1px solid black;">'.$contentO.'</div>';
130→                    ++$no;
131→                    $n = '<p><b>'.$no.'、 '.$nickname.'</b></p>';
132→                    $newContent = $n.$contentO;
133→
134→                    if (strlen($content) + strlen($newContent) > $oneEmailLimit) {
135→                        ++$emailAllCount;
136→                        $content = '';
137→                    }
138→                    $content .= $newContent;
139→                }
140→                ++$emailAllCount;
141→
142→                $content = '<p >Dear '.$nicknameOk.',</p><p >以下是您关注同事'.$msg2.'的日报：</p>';
143→                // d
144→                $no = 0;
145→                foreach ($data['reports']['report_list'] as $report) {
146→                    $nickname1 = '';
147→                    if (empty($report['data']['nickname'])) {
148→                        if (!empty($report['sfuser_id'])) {
149→                            $sfuser_id1 = Sfuser::where('id', $report['sfuser_id'])->first();
150→                            if (!empty($sfuser_id1)) {
151→                                $nickname1 = $sfuser_id1->nickname;
152→                            }
153→                        }
154→                    } else {
155→                        $nickname1 = $report['data']['nickname'];
156→                    }
157→                    if (empty($nickname1)) {
158→                        info('发送日报邮件 空数据 '.my_json_encode($report));
159→                        continue;
160→                    }
161→                    $nickname = $this->encr($nickname1);
162→                    $contentO = $this->encr($report['content']);
163→                    $contentO = '<div style="border: 1px solid black;">'.$contentO.'</div>';
164→                    ++$no;
165→                    $n = '<p><b>'.$no.'、 '.$nickname.'</b></p>';
166→                    $newContent = $n.$contentO;
167→                    if (strlen($content) + strlen($newContent) > $oneEmailLimit) {
168→                        ++$emailOne;
169→                        $subject = '【'.$full_date.'】 日报汇总'.($emailAllCount > 1 ? '（'.$emailOne.'/'.$emailAllCount.'）'
170→                                    : '');
171→                        info('发送日报邮件'.$subject.' to '.implode(',', $toEmails));
172→                        sendEmail($content, $subject, [$sfuser_token], filter: 'emails', filterMap: ['emails' => $toEmails]);
173→                        info('发送日报邮件成功'.$subject.' to '.implode(',', $toEmails));
174→                        $content = '';
175→                    }
176→                    $content .= $newContent;
177→                }
178→                ++$emailOne;
179→                $subject = '【'.$full_date.'】 日报汇总'.($emailAllCount > 1 ? '（'.$emailOne.'/'.$emailAllCount.'）'
180→                            : '');
181→                if (!empty($data['lack_report']) && !empty($data['lack_report'][$full_date])) {
182→                    foreach ($data['lack_report'][$full_date] as $lack_report) {
183→                        ++$no;
184→                        $nickname2 = $this->encr($lack_report);
185→                        $n2 = '<p><b>'.$no.'、 '.$nickname2.'</b></p>';
186→                        $content .= $n2.'未提交日报';
187→                    }
188→                    $content .= '<br>';
189→                }
190→                $content .= '<br><span>👉点击快速跳转OA查看更多日报详情：<a href="'.'http://oa.xinyoudi.com'.'/home/#/oa-dailyReport/othersReport">'.'http://oa.xinyoudi.com'.'/home/#/oa-dailyReport/othersReport</a></span><br><br><br><br>';
191→                info('发送日报邮件'.$subject.' to '.implode(',', $toEmails));
192→                sendEmail($content, $subject, [$sfuser_token], filter: 'emails', filterMap: ['emails' => $toEmails]);
193→                info('发送日报邮件成功'.$subject.' to '.implode(',', $toEmails));
194→            } catch (\Throwable $e) {
195→                info(__METHOD__.': 发送日报邮件 Email Fails. '.my_json_encode($mc).$e->getMessage().$e->getTraceAsString());
196→                continue;
197→            }
198→        }
199→        info('发送日报邮件 Job 结束');
200→        info('[ScheduleJob][DailyReportJob] finished #4');
201→        return true;
202→    }
